                key={filter}
                onClick={() => setActiveFilter(filter)}
                className={`px-6 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all ${
                  activeFilter === filter 
                    ? 'bg-black text-white dark:bg-white dark:text-black shadow-lg' 
