            <Route path="/unique-offer-v2" element={<UniqueOfferV2 />} />
            <Route path="/offres" element={<Offers />} />
            <Route path="/toolkit" element={<MetaDesignToolkit />} />
            <Route path="/toolkit/:id" element={<ToolkitDetail />} />
            <Route path="/events" element={<Events />} />
